import json
import sys
from .core import load_items, summarize


def main(argv=None):
    argv = list(argv or sys.argv[1:])
    if not argv:
        raise SystemExit('usage: inventory <csv>')
    print(json.dumps(summarize(load_items(argv[0])), sort_keys=True))


if __name__ == '__main__':
    main()

