def parse_settings(text: str):
    data = {}
    section = data
    for raw in text.splitlines():
        line = raw.strip()
        if not line or line.startswith('#'):
            continue
        if line.startswith('[') and line.endswith(']'):
            name = line[1:-1]
            section = data.setdefault(name, {})
            continue
        if '=' in line:
            key, value = line.split('=', 1)
            section[key.strip()] = value.strip()
    return data

