from settings_parser import parse_settings


def test_flat_keys_before_sections():
    assert parse_settings('debug=true\n') == {'debug': True}


def test_sections_and_numbers():
    parsed = parse_settings('[server]\nport=8080\nhost=localhost\n[limits]\nworkers=4\n')
    assert parsed['server'] == {'port': 8080, 'host': 'localhost'}
    assert parsed['limits'] == {'workers': 4}


def test_dotted_section_names_are_nested():
    parsed = parse_settings('[database.primary]\nhost=db.local\nport=5432\n')
    assert parsed == {'database': {'primary': {'host': 'db.local', 'port': 5432}}}
